    function _batchCopyTo() {
        const cards = _getSelectedCards();
        if (!cards.length) { if (typeof showToast === 'function') showToast('未选择字卡'); return; }

        _showBatchModeChoice('复制到…', () => {
            // 按模式导入
            const byMode = new Map();
            cards.forEach(({ mode, card }) => {
                const name = mode.name || '未命名';
                if (!byMode.has(name)) byMode.set(name, []);
                byMode.get(name).push({ text: cardText(card), keywords: [...(card.keywords || [])] });
            });
            _showConvPickerModal('复制到…', (convIds) => {
                const data = getData();
                let convCount = 0;
                convIds.forEach(cid => {
                    const targetConv = data.conversations.find(c => c.id === cid);
                    if (!targetConv) return;
                    byMode.forEach((modeCards, modeName) => {
                        let existing = targetConv.modes.find(m => m.name === modeName);
                        if (existing) { modeCards.forEach(c => existing.cards.push({ ...c })); }
                        else { targetConv.modes.push({ id: genId(), name: modeName, cards: modeCards.map(c => ({ ...c })), sequences: [] }); }
                    });
                    convCount++;
                });
                if (typeof saveData === 'function') saveData();
                if (typeof showToast === 'function') showToast(`已复制 ${byMode.size} 个模式（${cards.length} 张卡）到 ${convCount} 个对话`);
                _exitGlobalSelectMode();
            });
        }, () => {
            // 合并到指定模式
            _showTargetPickerModal('复制到…', (targets) => {
                const data = getData();
                targets.forEach(({ convId, modeIdx }) => {
                    const targetConv = data.conversations.find(c => c.id === convId);
                    if (!targetConv || !targetConv.modes[modeIdx]) return;
                    const targetMode = targetConv.modes[modeIdx];
                    cards.forEach(({ card }) => { targetMode.cards.push({ text: cardText(card), keywords: [...(card.keywords || [])] }); });
                });
                if (typeof saveData === 'function') saveData();
                if (typeof showToast === 'function') showToast(`已复制 ${cards.length} 张字卡到 ${targets.length} 个目标模式`);
                _exitGlobalSelectMode();
            });
        });
    }

    function _deleteFromSource(cards) {
        const data = getData();
        // 分组：模板库 vs 对话
        const bySource = new Map(); // key: "convId|mIdx" or "__lib__|gi"
        cards.forEach(({ isLib, conv, mIdx, cIdx }) => {
            const key = isLib ? `__lib__|${mIdx}` : `${conv.id}|${mIdx}`;
            if (!bySource.has(key)) bySource.set(key, []);
            bySource.get(key).push(cIdx);
        });
        bySource.forEach((indices, key) => {
            const [src, mi] = key.split('|');
            const miInt = parseInt(mi);
            if (src === '__lib__') {
                const gm = data.globalModes[miInt];
                if (gm) indices.sort((a, b) => b - a).forEach(i => gm.cards.splice(i, 1));
            } else {
                const conv = data.conversations.find(c => c.id === src);
                if (!conv || !conv.modes[miInt]) return;
                indices.sort((a, b) => b - a).forEach(i => conv.modes[miInt].cards.splice(i, 1));
            }
        });
    }

    function _batchMoveTo() {
        const cards = _getSelectedCards();
        if (!cards.length) { if (typeof showToast === 'function') showToast('未选择字卡'); return; }

        _showBatchModeChoice('移动到…', () => {
            // 按模式导入
            const byMode = new Map();
            cards.forEach(({ mode, card }) => {
                const name = mode.name || '未命名';
                if (!byMode.has(name)) byMode.set(name, []);
                byMode.get(name).push({ text: cardText(card), keywords: [...(card.keywords || [])] });
            });
            _showConvPickerModal('移动到…', (convIds) => {
                const data = getData();
                convIds.forEach(cid => {
                    const targetConv = data.conversations.find(c => c.id === cid);
                    if (!targetConv) return;
                    byMode.forEach((modeCards, modeName) => {
                        let existing = targetConv.modes.find(m => m.name === modeName);
                        if (existing) { modeCards.forEach(c => existing.cards.push({ ...c })); }
                        else { targetConv.modes.push({ id: genId(), name: modeName, cards: modeCards.map(c => ({ ...c })), sequences: [] }); }
                    });
                });
                _deleteFromSource(cards);
                if (typeof saveData === 'function') saveData();
                if (typeof showToast === 'function') showToast(`已移动 ${byMode.size} 个模式（${cards.length} 张卡）到 ${convIds.length} 个对话`);
                _exitGlobalSelectMode();
            });
        }, () => {
            // 合并到指定模式
            _showTargetPickerModal('移动到…', (targets) => {
                const data = getData();
                targets.forEach(({ convId, modeIdx }) => {
                    const targetConv = data.conversations.find(c => c.id === convId);
                    if (!targetConv || !targetConv.modes[modeIdx]) return;
                    const targetMode = targetConv.modes[modeIdx];
                    cards.forEach(({ card }) => { targetMode.cards.push({ text: cardText(card), keywords: [...(card.keywords || [])] }); });
                });
                _deleteFromSource(cards);
                if (typeof saveData === 'function') saveData();
                if (typeof showToast === 'function') showToast(`已移动 ${cards.length} 张字卡到 ${targets.length} 个目标模式`);
                _exitGlobalSelectMode();
            });
        });
    }

    function _batchDelete() {
        const cards = _getSelectedCards();
        if (!cards.length) { if (typeof showToast === 'function') showToast('未选择字卡'); return; }
        if (!confirm(`确定删除选中的 ${cards.length} 张字卡？`)) return;
        _deleteFromSource(cards);
        if (typeof saveData === 'function') saveData();
        if (typeof showToast === 'function') showToast(`已删除 ${cards.length} 张字卡`);
        _exitGlobalSelectMode();
    }

